const authData = $input.item.json;
const body = authData.body || {};

const userId = authData.user_id || '';
const month = body.month || '';
const industry = body.industry || '';
const platforms = body.platforms || [];
const pipelineRunId = body.pipeline_run_id || '';
const callbackUrl = body.callback_url || '';

return {
  json: {
    user_id: userId,
    month: month,
    industry: industry,
    platforms: platforms,
    pipeline_run_id: pipelineRunId,
    callback_url: callbackUrl
  }
};

const params = $('Extract Params').item.json;
const icpRaw = $('Read ICP').item.json;
const productsRaw = $input.item.json;

// Parse ICP data
let icp = {};
try {
  const icpArr = Array.isArray(icpRaw) ? icpRaw : [icpRaw];
  icp = icpArr[0] || {};
} catch(e) {
  icp = {};
}

// Parse products data
let products = [];
try {
  products = Array.isArray(productsRaw) ? productsRaw : (productsRaw ? [productsRaw] : []);
  // Filter out empty/error responses
  products = products.filter(p => p && p.id);
} catch(e) {
  products = [];
}

// Build product list for prompt
const productList = products.map((p, i) => {
  return `${i + 1}. **${p.name}** (ID: ${p.id})\n   Description: ${p.description || 'N/A'}\n   Price: ${p.price || 'N/A'}\n   Category: ${p.category || 'General'}\n   Features: ${p.features ? (Array.isArray(p.features) ? p.features.join(', ') : JSON.stringify(p.features)) : 'N/A'}`;
}).join('\n');

const productCount = products.length;
const month = params.month || new Date().toISOString().slice(0, 7);

// Build the comprehensive Claude prompt
const prompt = `You are an expert social media content strategist using the NETFLIX MODEL for content planning.

You are creating a monthly content campaign for a business. Generate a complete Netflix-model campaign structure.

## BUSINESS CONTEXT
- Industry: ${params.industry || 'General'}
- Month: ${month}
- ICP Summary: ${icp.icp_summary || 'General audience'}
- Content Pillars: ${icp.content_pillars ? JSON.stringify(icp.content_pillars) : 'Not available'}
- Pain Points: ${icp.pain_points ? JSON.stringify(icp.pain_points) : 'Not available'}
- Desires: ${icp.desires ? JSON.stringify(icp.desires) : 'Not available'}

## PRODUCTS/SERVICES (${productCount} total)
${productList || 'No products available - create generic content themes'}

## NETFLIX MODEL RULES

1. **SHOW NAME**: Create a catchy, branded show name for this month's campaign (e.g., "The Glow-Up Series", "Build Different", "The Founders Table")

2. **4 SEASONS** (1 per week), each with a progressive arc:
   - Season 1 (Week 1): "intro" -- Introduce the brand, products, and value proposition. Hook the audience.
   - Season 2 (Week 2): "deepen" -- Go deeper into product benefits, customer stories, expertise. Build trust.
   - Season 3 (Week 3): "challenge" -- Address objections, myths, comparisons. Overcome barriers.
   - Season 4 (Week 4): "celebrate" -- Success stories, community, future vision. Create loyalty.

3. **DAILY ASSIGNMENTS**: Each day gets exactly 1 product + 1 inspirational topic
   - 7 days per season = 28 days total
   - Products should cluster by theme coherence (similar products in same week when possible)
   ${productCount > 30 ? '- You have more than 30 products: select the top 30 most relevant to the ICP' : productCount > 0 ? '- You have fewer products than days: distribute products evenly, repeating as needed' : '- No products available: create topic-only assignments'}

4. **WEEKLY HOOKS**: Last day of each week teases the next season. Daily posts stand alone within their week.

## REQUIRED OUTPUT FORMAT

Return a JSON object with this EXACT structure:
{
  "show_name": "The [Catchy Name] Series",
  "show_concept": "Brief description of the month's overarching narrative (1-2 sentences)",
  "seasons": [
    {
      "week_number": 1,
      "theme_name": "Season 1: [Creative Name]",
      "inspirational_theme": "Introduction/Discovery theme description",
      "season_arc": "intro",
      "theme_description": "What this week covers and why it matters",
      "hook": "Weekly hook teasing next season (for last post of week)",
      "days": [
        {
          "day_number": 1,
          "product_id": "uuid-of-product-or-null",
          "product_name": "Product Name",
          "topic": "Inspirational daily topic tied to product + theme",
          "content_angle": "How to present this product through the theme lens"
        }
      ]
    }
  ]
}

Each season MUST have exactly 7 days. Each day MUST have a product_id (use actual UUIDs from the product list above), product_name, topic, and content_angle.

Return ONLY valid JSON. No markdown fences. No explanation.`;

return {
  json: {
    prompt: prompt,
    user_id: params.user_id,
    month: month,
    pipeline_run_id: params.pipeline_run_id,
    callback_url: params.callback_url,
    product_count: productCount
  }
};

const input = $input.item.json;
const promptData = $('Prepare Theme Prompt').item.json;

// Extract Claude response text
let raw = '';
try {
  raw = input.content[0].text;
} catch(e) {
  raw = JSON.stringify(input);
}

// Robust JSON parsing: try raw -> strip markdown fences -> regex extract
let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  // Strip markdown fences
  const stripped = raw.replace(/```(?:json)?\s*/g, '').replace(/```\s*$/g, '').trim();
  try {
    parsed = JSON.parse(stripped);
  } catch(e2) {
    // Extract first JSON object
    const match = stripped.match(/\{[\s\S]*\}/);
    if (match) {
      parsed = JSON.parse(match[0]);
    } else {
      throw new Error('Could not parse Claude response as JSON');
    }
  }
}

// Validate structure
if (!parsed.show_name) {
  throw new Error('Missing show_name in Claude response');
}
if (!parsed.seasons || !Array.isArray(parsed.seasons)) {
  throw new Error('Missing or invalid seasons array in Claude response');
}
if (parsed.seasons.length !== 4) {
  throw new Error('Expected 4 seasons, got ' + parsed.seasons.length);
}

// Validate each season has days
for (const season of parsed.seasons) {
  if (!season.days || !Array.isArray(season.days)) {
    throw new Error('Season ' + season.week_number + ' missing days array');
  }
  if (season.days.length < 7) {
    throw new Error('Season ' + season.week_number + ' has ' + season.days.length + ' days, expected 7');
  }
}

return {
  json: {
    show_name: parsed.show_name,
    show_concept: parsed.show_concept || '',
    seasons: parsed.seasons,
    user_id: promptData.user_id,
    month: promptData.month,
    pipeline_run_id: promptData.pipeline_run_id,
    callback_url: promptData.callback_url
  }
};

const campaignResult = $input.item.json;
const themeData = $('Parse Theme Response').item.json;

// Extract campaign_id from UPSERT response
let campaignId = '';
try {
  const row = Array.isArray(campaignResult) ? campaignResult[0] : campaignResult;
  campaignId = row.id || '';
} catch(e) {
  throw new Error('Could not extract campaign_id from UPSERT response');
}

if (!campaignId) {
  throw new Error('Campaign UPSERT returned empty id');
}

return {
  json: {
    campaign_id: campaignId,
    show_name: themeData.show_name,
    show_concept: themeData.show_concept,
    seasons: themeData.seasons,
    user_id: themeData.user_id,
    month: themeData.month,
    pipeline_run_id: themeData.pipeline_run_id,
    callback_url: themeData.callback_url
  }
};

const deleteResult = $input.item.json;
const data = $('Extract Campaign ID').item.json;

const themeRows = data.seasons.map(s => ({
  user_id: data.user_id,
  campaign_id: data.campaign_id,
  week_number: s.week_number,
  theme_name: s.theme_name,
  theme_description: s.theme_description || '',
  show_concept: data.show_concept || '',
  hook: s.hook || '',
  season_arc: s.season_arc || '',
  inspirational_theme: s.inspirational_theme || '',
  content_types: JSON.stringify(s.days)
}));

return {
  json: {
    theme_rows: themeRows,
    campaign_id: data.campaign_id,
    show_name: data.show_name,
    user_id: data.user_id,
    pipeline_run_id: data.pipeline_run_id,
    callback_url: data.callback_url
  }
};

const patchResult = $input.item.json;
const themeData = $('Prepare Theme Rows').item.json;

return {
  json: {
    campaign_id: themeData.campaign_id,
    show_name: themeData.show_name,
    themes_count: 4,
    pipeline_run_id: themeData.pipeline_run_id,
    callback_url: themeData.callback_url
  }
};

// Error handler: catches failures and calls callback with error status
const errorData = $input.item.json;

// Try to recover pipeline_run_id and callback_url from earlier nodes
let pipelineRunId = '';
let callbackUrl = '';
try {
  const params = $('Extract Params').item.json;
  pipelineRunId = params.pipeline_run_id || '';
  callbackUrl = params.callback_url || '';
} catch(e) {
  // Can't recover, will skip callback
}

return {
  json: {
    pipeline_run_id: pipelineRunId,
    callback_url: callbackUrl,
    error_message: 'Theme Generator failed: ' + (errorData.message || errorData.error || 'Unknown error')
  }
};
